class AwsCredentialManager(config: AwsConfig) extends CredentialManager {

  private var currentCredentialType: CredentialType = config.credentialType
  private var cachedProvider: Option[AwsCredentialsProvider] = None

  override def getCredentialsProvider(credentialType: CredentialType): AwsCredentialsProvider = {
    credentialType match {
      case StaticCredentials(accessKeyId, secretAccessKey) =>
        StaticCredentialsProvider.create(
          AwsBasicCredentials.create(accessKeyId, secretAccessKey)
        )
      case SessionCredentials(accessKeyId, secretAccessKey, sessionToken) =>
        StaticCredentialsProvider.create(
          AwsSessionCredentials.create(accessKeyId, secretAccessKey, sessionToken)
        )
      case ProfileCredentials(profileName) =>
        ProfileCredentialsProvider.create(profileName)
      case DefaultCredentials =>
        DefaultCredentialsProvider.create()
    }
  }

  override def assumeRole(roleArn: String, sessionName: String, durationSeconds: Int = 3600): Try[SessionCredentials] = {
    Try {
      val stsClient = StsClient.builder()
        .region(config.region)
        .credentialsProvider(getCredentialsProvider(currentCredentialType))
        .build()

      try {
        val request = AssumeRoleRequest.builder()
          .roleArn(roleArn)
          .roleSessionName(sessionName)
          .durationSeconds(durationSeconds)
          .build()

        val response = stsClient.assumeRole(request)
        val credentials = response.credentials()

        val sessionCreds = SessionCredentials(
          credentials.accessKeyId(),
          credentials.secretAccessKey(),
          credentials.sessionToken()
        )

        currentCredentialType = sessionCreds
        cachedProvider = Some(getCredentialsProvider(sessionCreds))

        sessionCreds
      } finally {
        stsClient.close()
      }
    }
  }

  override def refreshCredentials(): Try[AwsCredentialsProvider] = {
    Try {
      val provider = getCredentialsProvider(currentCredentialType)
      // Force credential resolution to validate
      provider.resolveCredentials()
      cachedProvider = Some(provider)
      provider
    }
  }

  def getCurrentProvider: AwsCredentialsProvider = {
    cachedProvider.getOrElse {
      val provider = getCredentialsProvider(currentCredentialType)
      cachedProvider = Some(provider)
      provider
    }
  }
}

